 5→interface NavHeaderProps extends SDUIComponentProps {
 6→  title: string;
 7→  showBack?: boolean;
 8→}
 9→
10→export default function NavHeaderAdapter({
11→  props,
12→}: {
13→  props: NavHeaderProps;
14→  context: SDUIContext;
15→}) {
16→  const { title, showBack = true } = props;
17→
18→  return (
19→    <Header
20→      title={title}
21→      iconLeft={showBack ? 'icon-back' : undefined}
22→      onBack={showBack ? () => {} : undefined}
23→    />
24→  );
25→}
