28→// FIXME: use something like "props: DUIProps<Foo, Bar>" during component
29→//  creation in order to avoid eliminate the use of "as SDUIComponentRenderer"
30→const adapters: Record<string, SDUIComponentRenderer> = {
31→  heading: HeadingAdapter as SDUIComponentRenderer,
32→  text: TextAdapter as SDUIComponentRenderer,
33→  balance_display: BalanceDisplayAdapter as SDUIComponentRenderer,
34→  points_input: PointsInputAdapter as SDUIComponentRenderer,
35→  button: ButtonAdapter as SDUIComponentRenderer,
36→  link: LinkAdapter as SDUIComponentRenderer,
37→  alert: AlertAdapter as SDUIComponentRenderer,
38→  list_text_icon: ListTextIconAdapter as SDUIComponentRenderer,
39→  separator: SeparatorAdapter as SDUIComponentRenderer,
40→  icon_text_row: IconTextRowAdapter as SDUIComponentRenderer,
41→  section_heading: SectionHeadingAdapter as SDUIComponentRenderer,
42→  rich_text: RichTextAdapter as SDUIComponentRenderer,
43→  voucher_card: VoucherCardAdapter as SDUIComponentRenderer,
44→  empty_state: EmptyStateAdapter as SDUIComponentRenderer,
45→  points_card: PointsCardAdapter as SDUIComponentRenderer,
46→  tab_bar: TabBarAdapter as SDUIComponentRenderer,
47→  transaction_item: TransactionItemAdapter as SDUIComponentRenderer,
48→  date_separator: DateSeparatorAdapter as SDUIComponentRenderer,
49→  detail_header: DetailHeaderAdapter as SDUIComponentRenderer,
50→  tag_label: TagLabelAdapter as SDUIComponentRenderer,
51→  key_value_row: KeyValueRowAdapter as SDUIComponentRenderer,
52→  card_activity: CardActivityAdapter as SDUIComponentRenderer,
53→  nav_header: NavHeaderAdapter as SDUIComponentRenderer,
54→};
55→
56→export function registerAllAdapters(): void {
57→  Object.entries(adapters).forEach(([type, renderer]) => {
58→    registerToDefault(type, renderer);
59→  });
60→}
61→
62→export { adapters };
